print(f"Generating {len(ITEMS)} commits...")
for day, hour, minute, path, content, msg in ITEMS:
    dt = datetime(2026, 3, day, hour, minute, random.randint(0, 59))
    w(path, content)
    git(msg, dt)

print(f"Done! Generated {count} commits.")
